VALUES
  ('bookkeeper-moex-01152', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '某自助餐店被稽徵機關查定每月銷售額為10萬元，試問該自助餐店應如何申報繳納營業稅？', '["每2個月為一期申報繳納百分之一的營業稅，共計2千元", "每2個月為一期申報繳納百分之五的營業稅，共計1萬元", "由主管稽徵機關，每3個月填發繳款書通知繳納一次，每期共計3千元", "由主管稽徵機關，每個月填發繳款書通知繳納一次，每月1千元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01153', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列有關營業人漏開統一發票或於統一發票上短開銷售額之處罰方 式何者錯誤？', '["除應就短漏開銷售額按規定稅率計算稅額繳納稅款外，處1倍至10倍罰鍰", "於法定申報期限前經查獲者，應就短漏開銷售額按規定稅率計算稅額繳納稅款，並按該稅額處5倍以下罰鍰", "前項處罰金額不得超過新臺幣100萬元", "一年內經查獲達3次者，並停止其營業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01154', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依統一發票使用辦法規定，營業人每筆銷售額與銷項稅額合計未滿新臺幣多少元，除買受人要求外，得 免逐筆開立發票？', '["50元", "100元", "200元", "500元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01155', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依統一發票使用辦法規定，下列那一選項不是主管稽徵機關停止營業人購買統一發票之原因？', '["開立不實統一發票", "受停止營業處分", "已變更課稅方式為查定課徵", "無進貨事實虛報進項稅額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01156', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依統一發票使用辦法規定，下列那一選項不得免用或免開統一發票？', '["公用事業。但經營本業以外之部分，不包括在內", "依法設立之免稅商店及離島免稅購物商店", "依法組織之慈善救濟事業標售或義賣之貨物與舉辦之義演，其收入除支付標售、義賣及義演之必要費 用外，全部供作該事業本身之用者", "營業人取得之賠償收入"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01157', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行規定，若財產為繼承人公同共有之遺產且該遺產為被繼承人單獨所有，納稅義務人申請以該財產 抵繳遺產稅條件：', '["繼承人之應繼分合計二分之一以上同意", "繼承人過半數及其應繼分合計過半數同意", "繼承人二分之一以上之同意", "繼承人三分之二以上之同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01158', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行規定，被繼承人死亡前因重病無法處理事務期間出售名下財產，其繼承人對該項出售財產價金不 能證明其用途者：', '["列入遺產課稅", "屬於不計入遺產總額", "列入贈與課稅", "屬於不計入贈與總額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01159', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '吉米為美國公民，因深愛臺灣在臺居住滿10年，但未歸化取得中華民國國籍。若吉米想要將財產贈與給 其子女與朋友，試問下列敘述何者正確？', '["吉米為外國人，所以其贈與財產不需繳納我國之贈與稅", "吉米在中華民國境內無住所而有居所，且在贈與行為發生前 2 年內，在中華民國境內居留時間合計逾 365天，所以吉米贈與其在中華民國境內外之財產，皆須申報繳納我國之贈與稅", "吉米只須就其贈與在中華民國境內之財產，申報繳納我國之贈與稅", "吉米只須就其贈與在中華民國境外之財產，申報繳納我國之贈與稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01160', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依遺產及贈與稅法規定，下列有關遺產稅免稅額與扣除額之敘述何者錯誤？', '["被繼承人如為經常居住中華民國境內之中華民國國民，得自遺產總額中減除免稅額1,200萬元", "被繼承人如為非中華民國國民，不得自遺產總額中減除免稅額1,200萬元", "被繼承人之喪葬費用可以扣除，但以在中華民國境內發生者為限", "被繼承人死亡前，未償之債務，具有確實之證明者可以扣除，但以在中華民國境內發生者為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01161', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依遺產及贈與稅法規定，下列有關遺產稅及贈與稅應納稅額之規定何者錯誤？', '["遺產稅及贈與稅納稅義務人，應於稽徵機關送達核定納稅通知書之日起2個月內，繳清應納稅款", "遺產稅或贈與稅應納稅額在30萬元以上，納稅義務人確有困難，不能一次繳納現金時，得於納稅期限 內，向該管稽徵機關申請，分18期以內繳納，每期間隔以不超過2個月為限", "遺產稅或贈與稅應納稅額在30萬元以上，納稅義務人確有困難，不能一次繳納現金時，得於納稅期限 內，就現金不足繳納部分申請以在中華民國境內、外之課徵標的物或納稅義務人所有易於變價及保管 之實物一次抵繳", "中華民國境內之課徵標的物其申請抵繳日之時價較死亡或贈與日之時價為低者，其得抵繳之稅額，以 該項財產價值占全部課徵標的物價值比例計算之應納稅額為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
